func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	profile := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
	}
	if _, err := o.Insert(profile); err != nil {
		return nil, err
	}
	return profile, nil
}

func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	placeholders := make([]string, len(usernames))
	args := make([]interface{}, 0, len(usernames)+3)
	for i, u := range usernames {
		placeholders[i] = "?"
		args = append(args, u)
	}
	args = append(args, startDate, endDate)

	whereClauses := []string{
		fmt.Sprintf("u.username IN (%s)", strings.Join(placeholders, ",")),
		"a.created_at BETWEEN ? AND ?",
	}
	if actionTypeFilter != "" {
		whereClauses = append(whereClauses, "a.action_type = ?")
		args = append(args, actionTypeFilter)
	}

	query := fmt.Sprintf(`
		SELECT 
			u.display_name AS display_name,
			a.action_type AS action_type,
			COUNT(*) AS total_actions,
			SUM(CASE WHEN a.success THEN 1 ELSE 0 END) AS success_count,
			AVG(a.duration_ms) AS avg_duration
		FROM user_activity a
		INNER JOIN user_profile u ON a.user_id = u.id
		WHERE %s
		GROUP BY u.display_name, a.action_type
	`, strings.Join(whereClauses, " AND "))

	var results []UserActivitySummary
	if _, err := o.Raw(query, args...).QueryRows(&results); err != nil {
		return nil, err
	}
	return results, nil
}

func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	allowedGroups := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}
	if !allowedGroups[groupByField] {
		return nil, fmt.Errorf("invalid groupByField: %s, must be one of department, role, display_name", groupByField)
	}

	deptPlaceholders := make([]string, len(departments))
	args := make([]interface{}, 0, len(departments))
	for i, dept := range departments {
		deptPlaceholders[i] = "?"
		args = append(args, dept)
	}

	query := fmt.Sprintf(`
		SELECT 
			u.%s AS group_value,
			COUNT(DISTINCT u.id) AS user_count,
			COUNT(a.id) AS total_activities
		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id
		WHERE u.department IN (%s)
		GROUP BY u.%s
	`, groupByField, strings.Join(deptPlaceholders, ","), groupByField)

	var rawResults []orm.Params // Fixed type to match Beego ORM's Values expectation
	if _, err := o.Raw(query, args...).Values(&rawResults); err != nil {
		return nil, err
	}

	results := make([]map[string]interface{}, len(rawResults))
	for i, row := range rawResults {
		groupValue := fmt.Sprintf("%v", row["group_value"])
		userCountStr := fmt.Sprintf("%v", row["user_count"])
		totalActivitiesStr := fmt.Sprintf("%v", row["total_activities"])

		userCount, err := strconv.Atoi(userCountStr)
		if err != nil {
			return nil, fmt.Errorf("invalid user_count value '%s': %w", userCountStr, err)
		}
		totalActivities, err := strconv.Atoi(totalActivitiesStr)
		if err != nil {
			return nil, fmt.Errorf("invalid total_activities value '%s': %w", totalActivitiesStr, err)
		}
		results[i] = map[string]interface{}{
			"group_value":       groupValue,
			"user_count":        userCount,
			"total_activities":  totalActivities,
		}
	}
	return results, nil
}

