func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	// Normalize timestamps to UTC to ensure consistent comparison with database storage
	startDate = startDate.UTC()
	endDate = endDate.UTC()

	// Build username placeholders and parameters
	placeholderList := make([]string, len(usernames))
	params := make([]interface{}, 0, len(usernames)+3)
	for i, uname := range usernames {
		placeholderList[i] = "?"
		params = append(params, uname)
	}

	// Build WHERE conditions
	conditions := []string{
		fmt.Sprintf("u.username IN (%s)", strings.Join(placeholderList, ",")),
		"a.created_at >= ?",
		"a.created_at <= ?",
	}
	params = append(params, startDate, endDate)

	if actionTypeFilter != "" {
		conditions = append(conditions, "a.action_type = ?")
		params = append(params, actionTypeFilter)
	}

	query := fmt.Sprintf(`
		SELECT 
			u.display_name AS display_name,
			a.action_type AS action_type,
			COUNT(*) AS total_actions,
			SUM(CASE WHEN a.success THEN 1 ELSE 0 END) AS success_count,
			AVG(a.duration_ms) AS avg_duration
		FROM user_activity a
		JOIN user_profile u ON a.user_id = u.id
		WHERE %s
		GROUP BY u.display_name, a.action_type
	`, strings.Join(conditions, " AND "))

	var results []UserActivitySummary
	if _, err := o.Raw(query, params...).QueryRows(&results); err != nil {
		return nil, err
	}
	return results, nil
}

