	UserId     int64     `orm:"column(user_id)"`
	ActionType string    `orm:"column(action_type)"`
	Resource   string    `orm:"column(resource)"`
	IpAddress  string    `orm:"column(ip_address)"`
	Duration   int       `orm:"column(duration_ms)"`
	Success    bool      `orm:"column(success)"`
	CreatedAt  time.Time `orm:"column(created_at);auto_now_add"`
}

type UserActivitySummary struct {
	DisplayName  string
	ActionType   string
	TotalActions int
	SuccessCount int
	AvgDuration  float64
}

func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
	}
	if _, err := o.Insert(user); err != nil {
		return nil, err
	}
	return user, nil
}

func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	placeholders := make([]string, len(usernames))
	for i := range placeholders {
		placeholders[i] = "?"
	}
	inClause := strings.Join(placeholders, ", ")

	query := fmt.Sprintf(`SELECT u.display_name, a.action_type, 
		COUNT(*) as total_actions, 
		SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, 
		AVG(a.duration_ms) as avg_duration
		FROM user_activity a 
		INNER JOIN user_profile u ON a.user_id = u.id
		WHERE u.username IN (%s) AND a.created_at BETWEEN ? AND ?`, inClause)

	params := make([]interface{}, 0, len(usernames)+3)
	for _, uname := range usernames {
		params = append(params, uname)
	}
	params = append(params, startDate, endDate)

	if actionTypeFilter != "" {
		query += " AND a.action_type = ?"
		params = append(params, actionTypeFilter)
	}

	query += " GROUP BY u.display_name, a.action_type"

	var summaries []UserActivitySummary
	if _, err := o.Raw(query, params...).QueryRows(&summaries); err != nil {
		return nil, err
	}
	return summaries, nil
}

func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	validFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}
	if !validFields[groupByField] {
		return nil, fmt.Errorf("invalid groupByField: %s, must be one of department, role, display_name", groupByField)
	}

	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	placeholders := make([]string, len(departments))
	for i := range placeholders {
		placeholders[i] = "?"
	}
	inClause := strings.Join(placeholders, ", ")

	query := fmt.Sprintf(`SELECT u.%s as group_value, 
		COUNT(DISTINCT u.id) as user_count, 
		COUNT(a.id) as total_activities
		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id
		WHERE u.department IN (%s)
		GROUP BY u.%s`, groupByField, inClause, groupByField)

	params := make([]interface{}, len(departments))
	for i, dept := range departments {
		params[i] = dept
	}

	var results []orm.Params
	if _, err := o.Raw(query, params...).Values(&results); err != nil {
		return nil, err
	}

	// Convert []orm.Params to []map[string]interface{} for return type compatibility
	convertedResults := make([]map[string]interface{}, len(results))
	for i, row := range results {
		convertedResults[i] = map[string]interface{}(row)
	}
	return convertedResults, nil
}

