	_, err := o.Raw(sql, args...).Values(&ormResults)
	if err != nil {
		return nil, err
	}

	// Convert orm.Params to map[string]interface{} for return type compatibility
	results := make([]map[string]interface{}, len(ormResults))
	for i, params := range ormResults {
		results[i] = map[string]interface{}(params)
	}
	return results, nil
